// ──────────────────────────────────────────────
// 接收 Midas 发布结果，提取 postId
// 输入: { postId, subredditName, authorRole }
// ──────────────────────────────────────────────

const pubResult = $input.first().json;

return {
  postId: pubResult.postId || pubResult.id,
  subreddit: pubResult.subredditName || pubResult.subreddit,
  author: pubResult.authorRole || pubResult.author
};

// ──────────────────────────────────────────────
// API Key 可用性校验
// 如果没有任何 Embedding API Key，提前终止
// ──────────────────────────────────────────────

const apiKey = $env.EMBEDDING_API_KEY || $env.OPENAI_API_KEY || $env.DEEPSEEK_API_KEY;

if (!apiKey) {
  return {
    _embedding_error: true,
    _error_message: '⚠️ 未配置 Embedding API Key。请在 .env 中设置 EMBEDDING_API_KEY 或 OPENAI_API_KEY。向量化已跳过。',
    postId: $input.first().json.postId,
    _skip: true
  };
}

return $input.first().json;

// ──────────────────────────────────────────────
// 跳过 embedding，输出友好提示
// ──────────────────────────────────────────────

const data = $input.first().json;

console.warn(`[Embedding] Skipped for post ${data.postId}: ${data._error_message}`);

return {
  status: 'skipped',
  postId: data.postId,
  reason: 'no_api_key',
  message: data._error_message
};

// ──────────────────────────────────────────────
// 将文章内容按语义切片 (Chunking)
// 每个切片独立编码，取平均向量
// ──────────────────────────────────────────────

const post = $input.first().json;
const content = typeof post.embedding === 'string' ? post.embedding : (post.content || post.title || '');

// 简单切片: 按 ## 标题分割，每段 ≤ 2000 字符
function chunkText(text, maxLen = 2000) {
  if (!text || typeof text !== 'string') return [text || ''];
  const sections = text.split(/(?=^## )/m);
  const chunks = [];
  for (const sec of sections) {
    if (sec.length <= maxLen) {
      if (sec.trim()) chunks.push(sec.trim());
    } else {
      // 按段落再切
      const paras = sec.split(/\n\n+/);
      let cur = '';
      for (const p of paras) {
        if ((cur + p).length > maxLen && cur) {
          chunks.push(cur.trim());
          cur = p;
        } else {
          cur += (cur ? '\n\n' : '') + p;
        }
      }
      if (cur.trim()) chunks.push(cur.trim());
    }
  }
  return chunks.filter(c => c.length > 50);
}

const chunks = chunkText(content);

return chunks.map((chunk, i) => ({
  postId: post.postId,
  chunkIndex: i,
  totalChunks: chunks.length,
  text: chunk,
  // 为每个 chunk 构建 embedding 请求
  _embInput: chunk.substring(0, 8000)  // API 限制 8192 tokens
}));

// ──────────────────────────────────────────────
// 收集所有 chunk 的 embedding 向量
// 取平均值作为整篇文章的表示
// ──────────────────────────────────────────────

const items = $input.all();
const vectors = [];

for (const item of items) {
  const resp = item.json;
  const emb = resp.data?.[0]?.embedding;
  if (emb && Array.isArray(emb)) {
    vectors.push(emb);
  }
}

if (vectors.length === 0) {
  throw new Error('No embeddings generated');
}

// 平均池化
const dim = vectors[0].length;
const averaged = new Array(dim).fill(0);
for (const v of vectors) {
  for (let i = 0; i < dim; i++) {
    averaged[i] += v[i] / vectors.length;
  }
}

// 归一化到单位向量
const norm = Math.sqrt(averaged.reduce((s, x) => s + x * x, 0));
const normalized = norm > 0 ? averaged.map(x => x / norm) : averaged;

return {
  postId: items[0]?.json?.postId,
  embedding: normalized,
  model: 'text-embedding-3-small',
  chunks_encoded: vectors.length
};

// ──────────────────────────────────────────────
// 嵌入完成，输出摘要
// ──────────────────────────────────────────────

const result = $input.first().json;

return {
  pipeline: 'nexus-embedding',
  status: 'stored',
  postId: result.postId,
  dimensions: result.dimensions,
  model: result.model
};
